module shift_register(clk, reset, data_out);  

    input  clk;  
    input  reset;  
    output  [2:0] data_out;  
    reg   [2:0] data_out; 
    initial data_out = 0;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
        begin
            if (reset)
                data_out <= 0;
            else
                data_out <= data_out << 1;
        end  

endmodule
